try:
    import openpyxl
    from openpyxl.styles import PatternFill, Font, Alignment
    from openpyxl.utils import get_column_letter
except ImportError:
    print("pip install openpyxl"); sys.exit(1)

DNA_FILE = "CONTENT_DNA.xlsx"

COLORS = {
    "Ситуации":    "7C3AED","Боли":       "DC2626",
    "Режимы":      "0891B2","Индустрии":  "16A34A",
    "Персонажи":   "D97706","Платформы":  "2563EB",
    "Инструменты": "9333EA","Журнал":     "64748B",
}

def hfill(c): return PatternFill("solid", fgColor=c)
def hfont(bold=False, size=10, color="000000"): return Font(bold=bold, size=size, color=color)
def wrap(): return Alignment(wrap_text=True, vertical="top")
def head_align(): return Alignment(horizontal="center", vertical="center", wrap_text=True)

def style_sheet(ws, headers, sheet_key, widths=None):
    color = COLORS.get(sheet_key, "334155")
    for i, h in enumerate(headers, 1):
        c = ws.cell(row=1, column=i, value=h)
        c.fill = hfill(color); c.font = hfont(True, 10, "FFFFFF"); c.alignment = head_align()
        if widths and i-1 < len(widths):
            ws.column_dimensions[get_column_letter(i)].width = widths[i-1]
    ws.row_dimensions[1].height = 22; ws.freeze_panes = "A2"

def append_rows(ws, rows):
    for r in rows:
        ws.append(r)
        for cell in ws[ws.max_row]: cell.alignment = wrap()

# ── СИТУАЦИИ ──────────────────────────────────────────────────────
