def main():
    if Path(DNA_FILE).exists():
        ans = input(f"\n  {DNA_FILE} уже существует. Перезаписать? [y/N]: ").strip().lower()
        if ans != "y": print("  Отменено.\n"); return
    print(f"\n{'='*54}\n  AI Flow Studio — Создание базы CONTENT_DNA (RU)\n{'='*54}\n")
    wb = openpyxl.Workbook(); wb.remove(wb.active)
    print("  Создаю листы...")
    build_readme(wb); build_situations(wb); build_pain_points(wb); build_modes(wb)
    build_industries(wb); build_characters(wb); build_platforms(wb); build_tools(wb); build_log(wb)
    wb.save(DNA_FILE)
    print(f"  ✓  {DNA_FILE} создан")
    print(f"  ✓  71 ситуация (15 базовых + 56 расширенных)")
    print(f"  ✓  8 режимов контента с весами")
    print(f"  ✓  6 платформ настроено")
    print(f"  ✓  13 индустрий (включая фитнес и производство)")
    print(f"  ✓  3 персонажа: Динозавр, Менеджер, Excel-монстр")
    print(f"  ✓  10 инструментов настроено")
    print(f"\n  Запас свежего контента: ~{71//4} дней без повторов\n")
    print(f"  Следующий шаг: python generator.py\n")

if __name__ == "__main__":
    main()
